 1	import { Dropdown, DropdownItem, MenuToggle, MenuToggleElement } from '@patternfly/react-core';
 2	import * as React from 'react';
 3	import { useTranslation } from 'react-i18next';
 4	import { FlowScope } from '../../model/flow-query';
 5	import { ScopeConfigDef } from '../../model/scope';
 6	
 7	export interface ScopeDropdownProps {
 8	  selected: FlowScope;
 9	  setScopeType: (v: FlowScope) => void;
10	  id?: string;
11	  scopes: ScopeConfigDef[];
12	}
13	
14	export const ScopeDropdown: React.FC<ScopeDropdownProps> = ({ selected, setScopeType, id, scopes }) => {
15	  const { t } = useTranslation('plugin__netobserv-plugin');
16	  const [isOpen, setOpen] = React.useState(false);
17	
18	  return (
19	    <Dropdown
20	      data-test={id}
21	      id={id}
22	      popperProps={{
23	        position: 'right'
24	      }}
25	      isOpen={isOpen}
26	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
27	        <MenuToggle
28	          ref={toggleRef}
29	          data-test={`${id}-dropdown`}
30	          id={`${id}-dropdown`}
31	          isExpanded={isOpen}
32	          onClick={() => setOpen(!isOpen)}
33	          onBlur={() => setTimeout(() => setOpen(false), 500)}
34	        >
35	          {scopes.find(sc => sc.id === selected)?.name || t('n/a')}
36	        </MenuToggle>
37	      )}
38	    >
39	      {scopes.map(sc => (
40	        <DropdownItem
41	          data-test={sc.id}
42	          id={sc.id}
43	          key={sc.id}
44	          onClick={() => {
45	            setOpen(false);
46	            setScopeType(sc.id);
47	          }}
48	        >
49	          {sc.name}
50	        </DropdownItem>
51	      ))}
52	    </Dropdown>
53	  );
54	};
55	
56	export default ScopeDropdown;

